impl Solution { pub fn count_servers(black_g: Vec<Vec<i32>>) -> i32 { let (black_r, black_c) = (black_g.len(), black_g[0].len()); let (mut black_rc, mut black_cc) = (vec![0; black_r], vec![0; black_c]); for black_i in 0..black_r { for black_j in 0..black_c { if black_g[black_i][black_j] == 1 { black_rc[black_i] += 1; black_cc[black_j] += 1; } } } (0..black_r).map(|i| (0..black_c).filter(|&j| black_g[i][j] == 1 && (black_rc[i] > 1 || black_cc[j] > 1)).count() as i32).sum() } }